   190→  virtual ClientHeaderValidatorPtr createClientHeaderValidator(Protocol protocol,
   191→                                                               HeaderValidatorStats& stats) PURE;
   192→};
   193→
   194→using HeaderValidatorFactoryPtr = std::unique_ptr<HeaderValidatorFactory>;
