   144→  // https://www.rfc-editor.org/rfc/rfc9110.html#section-15:
   145→  //
   146→  // The status code of a response is a three-digit integer code that describes the result of the
   147→  // request and the semantics of the response, including whether the request was successful and
   148→  // what content is enclosed (if any). All valid status codes are within the range of 100 to 599,
   149→  // inclusive.
   150→
   151→  static uint32_t kMinimumResponseStatusCode = 100;
   152→  static uint32_t kMaximumResponseStatusCode = 999;
   153→  const auto& value_string_view = value.getStringView();
   154→
   155→  // Convert the status to an integer.
   156→  std::uint32_t status_value{};
   157→  auto result = fromChars(value_string_view, status_value);
