   318→void ConnectionManagerUtility::cleanInternalHeaders(
   319→    RequestHeaderMap& request_headers, bool edge_request,
   320→    const std::list<Http::LowerCaseString>& internal_only_headers) {
   321→  if (edge_request) {
   322→    // Headers to be stripped from edge requests, i.e. to sanitize so
   323→    // clients can't inject values.
   324→    request_headers.removeEnvoyDecoratorOperation();
   325→    request_headers.removeEnvoyDownstreamServiceCluster();
   326→    request_headers.removeEnvoyDownstreamServiceNode();
   327→    request_headers.removeEnvoyOriginalPath();
   328→  }
   329→
   330→  // Headers to be stripped from edge *and* intermediate-hop external requests.
   331→  // TODO: some of these should only be stripped at edge, i.e. moved into
   332→  // the block above.
   333→  request_headers.removeEnvoyRetriableStatusCodes();
   334→  request_headers.removeEnvoyRetriableHeaderNames();
   335→  request_headers.removeEnvoyRetryOn();
   336→  request_headers.removeEnvoyRetryGrpcOn();
   337→  request_headers.removeEnvoyMaxRetries();
   338→  request_headers.removeEnvoyUpstreamAltStatName();
   339→  request_headers.removeEnvoyUpstreamRequestTimeoutMs();
   340→  request_headers.removeEnvoyUpstreamRequestPerTryTimeoutMs();
   341→  request_headers.removeEnvoyUpstreamRequestTimeoutAltResponse();
   342→  request_headers.removeEnvoyExpectedRequestTimeoutMs();
   343→  request_headers.removeEnvoyForceTrace();
   344→  request_headers.removeEnvoyIpTags();
   345→  request_headers.removeEnvoyOriginalUrl();
   346→  request_headers.removeEnvoyHedgeOnPerTryTimeout();
   347→
   348→  for (const LowerCaseString& header : internal_only_headers) {
   349→    request_headers.remove(header);
   350→  }
   351→}
