   172→HeaderValidator::HeaderEntryValidationResult
   173→HeaderValidator::validateGenericHeaderName(const HeaderString& name) {
   174→  // Verify that the header name is valid. This also honors the underscore in
   175→  // header configuration setting.
   176→  //
   177→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-5.1:
   178→  //
   179→  // header-field   = field-name ":" OWS field-value OWS
   180→  // field-name     = token
   181→  // token          = 1*tchar
   182→  //
   183→  // tchar          = "!" / "#" / "$" / "%" / "&" / "'" / "*"
   184→  //                / "+" / "-" / "." / "^" / "_" / "`" / "|" / "~"
   185→  //                / DIGIT / ALPHA
   186→  //                ; any VCHAR, except delimiters
   187→  const auto& key_string_view = name.getStringView();
   188→  // This header name is initially invalid if the name is empty.
   189→  if (key_string_view.empty()) {
   190→    return {HeaderEntryValidationResult::Action::Reject,
   191→            UhvResponseCodeDetail::get().EmptyHeaderName};
   192→  }
   193→
   194→  const bool reject_header_names_with_underscores =
   195→      config_.headers_with_underscores_action() == HeaderValidatorConfig::REJECT_REQUEST;
   196→  bool is_valid = true;
   197→  bool reject_due_to_underscore = false;
   198→  char c = '\0';
   199→
   200→  for (auto iter = key_string_view.begin();
   201→       iter != key_string_view.end() && is_valid && !reject_due_to_underscore; ++iter) {
   202→    c = *iter;
   203→    if (c != '_') {
   204→      is_valid &= testCharInTable(::Envoy::Http::kGenericHeaderNameCharTable, c);
   205→    } else {
   206→      reject_due_to_underscore = reject_header_names_with_underscores;
   207→    }
   208→  }
   209→
   210→  if (!is_valid) {
   211→    return {HeaderEntryValidationResult::Action::Reject,
   212→            UhvResponseCodeDetail::get().InvalidNameCharacters};
   213→  }
   214→
   215→  if (reject_due_to_underscore) {
   216→    stats_.incRequestsRejectedWithUnderscoresInHeaders();
   217→    return {HeaderEntryValidationResult::Action::Reject,
   218→            UhvResponseCodeDetail::get().InvalidUnderscore};
   219→  }
   220→
   221→  return HeaderEntryValidationResult::success();
