   278→HeaderValidator::HeaderValueValidationResult
   279→HeaderValidator::validateHostHeader(const HeaderString& value) {
   280→  // From RFC 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-7.2,
   281→  // and RFC 3986, https://datatracker.ietf.org/doc/html/rfc3986#section-3.2.2:
   282→  //
   283→  // Host       = uri-host [ ":" port ]
   284→  // uri-host   = IP-literal / IPv4address / reg-name
   285→  //
   286→  // TODO(#22859, #23314) - Fully implement IPv6 address validation
   287→  const auto host = value.getStringView();
   288→  if (host.empty()) {
   289→    return {HeaderValueValidationResult::Action::Reject, UhvResponseCodeDetail::get().InvalidHost};
   290→  }
   291→
   292→  // Check if the host/:authority contains the deprecated userinfo component. This is based on RFC
   293→  // 9110, https://www.rfc-editor.org/rfc/rfc9110.html#section-4.2.4:
   294→  //
   295→  // Before making use of an "http" or "https" URI reference received from an untrusted source, a
   296→  // recipient SHOULD parse for userinfo and treat its presence as an error; it is likely being
   297→  // used to obscure the authority for the sake of phishing attacks.
   298→  auto user_info_delimiter = host.find('@');
   299→  if (user_info_delimiter != absl::string_view::npos) {
   300→    // :authority cannot contain user info, reject the header
   301→    return {HeaderValueValidationResult::Action::Reject,
   302→            UhvResponseCodeDetail::get().InvalidHostDeprecatedUserInfo};
   303→  }
   304→
   305→  // Determine if the host is in IPv4, reg-name, or IPv6 form.
   306→  auto result = host.at(0) == '[' ? validateHostHeaderIPv6(host) : validateHostHeaderRegName(host);
   307→  if (!result.ok()) {
   308→    return {HeaderValueValidationResult::Action::Reject, result.details()};
   309→  }

